def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 8):
            weight = 1 / (j ** 1.5)
            term = (ratio ** j) * weight
            if j % 2 == 0:
                term *= 1.2
            else:
                term *= 0.8
            score += term
        remaining = capacity - item
        if remaining < 0.05 * capacity:
            score *= 2
        elif remaining < 0.15 * capacity:
            score *= 1.3
        else:
            for k in range(1, 4):
                if remaining > k * 0.3 * capacity:
                    score *= 0.9 ** k
        if item > 0.5 * capacity:
            score += np.log1p(item)
        if i > 0:
            prev_capacity = bins[i-1]
            if prev_capacity > capacity:
                score *= 1.1
            else:
                score *= 0.95
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 3
    return priorities
